INSERT INTO `service_3` (`service_id`, `service_name`, `description`, `price`, `category`, `rating`) VALUES
(1, 'Cognitive Behavioral Therapy (CBT) Session', 'Structured CBT session to challenge negative thought patterns and build healthier behavior.', 123.45, 5, 4.9),
(2, 'Art Therapy - Canvas Painting', 'A painting-based session to express emotions and reduce stress through visual art.', 183.79, 5, 4.7),
(3, 'Art Therapy - Craft-Based Expression', 'Use of craft materials for emotional expression and therapeutic creativity.', 65.18, 2, 4.1),
(4, 'Guided Meditation for Anxiety', 'Breath-focused meditation designed to reduce anxiety and enhance calmness.', 48.42, 1, 4.9),
(5, 'Mindfulness and Breathwork Practice', 'Mindfulness techniques including breathwork and body scan for grounding.', 133.91, 5, 3.8),
(6, 'Stress Relief Coaching and Lifestyle Planning', 'Personal coaching to manage stress, build routines, and improve resilience.', 175.31, 1, 4.7),
(7, 'Therapeutic Journaling Workshop', 'A guided writing experience for reflection and emotional release.', 40.41, 3, 3.8),
(8, 'Restorative Yoga for Sleep', 'Relaxing yoga sequence to support better sleep and physical recovery.', 184.34, 1, 4.8),
(9, 'Power Yoga for Strength and Flexibility', 'High-energy yoga focused on strength building and endurance.', 43.42, 5, 3.5),
(10, 'Sound Therapy with Tibetan Singing Bowls', 'Immersive session using Tibetan bowls to balance energy and reduce tension.', 155.18, 5, 3.6);
